/// Safe parameter readers for uniform setters.
const double _maxSafeIntegerDouble = 9007199254740991.0;

bool _isSafeIntegerDouble(double value) {
  return value.isFinite && value.abs() <= _maxSafeIntegerDouble;
}

double readDouble(Map<String, Object> params, String key, double fallback) {
  final value = params[key];
  if (value is int) return value.toDouble();
  if (value is double && value.isFinite) return value;
  return fallback;
}

int readInt(Map<String, Object> params, String key, int fallback) {
  final value = params[key];
  if (value is int) return value;
  if (value is double && _isSafeIntegerDouble(value)) return value.round();
  return fallback;
}

import 'package:flutter_test/flutter_test.dart';

import 'package:flutter_fractals/core/modules/param_reader.dart';

void main() {
  group('readDouble', () {
    test('accepts finite int and double values', () {
      expect(readDouble({'power': 8}, 'power', 2.0), 8.0);
      expect(readDouble({'power': 3.5}, 'power', 2.0), 3.5);
    });

    test('falls back for missing, non-numeric, and non-finite values', () {
      expect(readDouble(const {}, 'power', 2.0), 2.0);
      expect(readDouble({'power': '8'}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.nan}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.infinity}, 'power', 2.0), 2.0);
      expect(readDouble({'power': double.negativeInfinity}, 'power', 2.0), 2.0);
    });
  });

  group('readInt', () {
    test('accepts integer values and rounds finite doubles', () {
      expect(readInt({'iterations': 120}, 'iterations', 80), 120);
      expect(readInt({'iterations': 120.4}, 'iterations', 80), 120);
      expect(readInt({'iterations': 120.5}, 'iterations', 80), 121);
    });

    test('falls back for missing, non-numeric, and non-finite values', () {
      expect(readInt(const {}, 'iterations', 80), 80);
      expect(readInt({'iterations': '120'}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.nan}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.infinity}, 'iterations', 80), 80);
      expect(readInt({'iterations': double.negativeInfinity}, 'iterations', 80),
          80);
    });

    test('falls back for finite doubles outside integer range', () {
      expect(readInt({'iterations': 1e100}, 'iterations', 80), 80);
      expect(readInt({'iterations': -1e100}, 'iterations', 80), 80);
    });
  });
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';

/// Common parameter builders shared across many 2D modules.
///
/// Keep these helpers small and stable; they are used in tests and codegen later.
class CommonFractalParams {
  static const int paletteCount = 64;

  static FractalParameter iterations({
    required num defaultValue,
    num min = 20,
    num max = 5000,
  }) {
    return FractalParameter(
      id: 'iterations',
      label: (l10n) => l10n.paramIterations,
      type: FractalParamType.integer,
      min: min.toDouble(),
      max: max.toDouble(),
      step: 1,
      defaultValue: defaultValue,
    );
  }

  static FractalParameter bailout({
    required double defaultValue,
    double min = 2.0,
    double max = 8.0,
  }) {
    return FractalParameter(
      id: 'bailout',
      label: (l10n) => l10n.paramBailout,
      type: FractalParamType.float,
      min: min,
      max: max,
      step: 0.1,
      defaultValue: defaultValue,
    );
  }

  static FractalParameter colorScheme4({Object defaultValue = 0, num max = 3}) {
    return FractalParameter(
      id: 'colorScheme',
      label: (l10n) => l10n.paramColorScheme,
      type: FractalParamType.enumeration,
      min: 0,
      max: max.toDouble(),
      step: 1,
      defaultValue: defaultValue,
      options: [
        FractalParamOption(value: 0, label: (l10n) => l10n.colorFire),
        FractalParamOption(value: 1, label: (l10n) => l10n.colorOcean),
        FractalParamOption(value: 2, label: (l10n) => l10n.colorPsychedelic),
        FractalParamOption(value: 3, label: (l10n) => l10n.colorGrayscale),
      ],
    );
  }

  /// Color cycle speed for palette-texture shaders (G15).
  ///
  /// A value of 0.0 = static (no cycling); 0.1 = ~1 full cycle every 10 s.
  /// Only meaningful at deep zoom where the perturbation shader is active
  /// (zoom >= 5e6). The controls panel shows this slider for all modules that
  /// include it, but it only has visible effect in the perturbation path.
  static FractalParameter colorCycleSpeed() {
    return FractalParameter(
      id: 'colorCycleSpeed',
      label: (l10n) => 'Color speed',
      type: FractalParamType.float,
      min: 0.0,
      max: 0.2,
      step: 0.001,
      defaultValue: 0.0,
    );
  }

  static FractalParameter colorScheme64({int defaultValue = 0}) {
    // Keep the first 4 as named palettes for continuity.
    final options = <FractalParamOption>[
      FractalParamOption(value: 0, label: (l10n) => l10n.colorFire),
      FractalParamOption(value: 1, label: (l10n) => l10n.colorOcean),
      FractalParamOption(value: 2, label: (l10n) => l10n.colorPsychedelic),
      FractalParamOption(value: 3, label: (l10n) => l10n.colorGrayscale),
      // Remaining palettes are numbered. Keep labels simple for screen readers.
      // Palette 5 reserved for legacy Phoenix palette name.
      FractalParamOption(value: 4, label: (l10n) => l10n.colorPhoenix),
      for (int i = 5; i < paletteCount; i++)
        FractalParamOption(
          value: i,
          label: (AppLocalizations l10n) => 'Palette ${i + 1}',
        ),
    ];

    return FractalParameter(
      id: 'colorScheme',
      label: (l10n) => l10n.paramColorScheme,
      type: FractalParamType.enumeration,
      min: 0,
      max: paletteCount - 1,
      step: 1,
      defaultValue: defaultValue,
      options: options,
    );
  }
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/builders/built_in_preset_contract.dart';
import 'package:flutter_fractals/core/modules/builders/uniform_layout.dart';
import 'package:flutter_fractals/core/modules/common_params.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/param_reader.dart';
import 'package:vector_math/vector_math.dart';

/// Declarative config for a standard 2D escape-time fractal.
///
/// Adding a new escape-time fractal = one [EscapeTimeConfig] + one .frag shader.
/// No Dart module file needed.
class EscapeTimeConfig {
  final String id;
  final String name;
  final ModuleNameBuilder? displayName;
  final String shaderAsset;
  final double defaultIterations;
  final double defaultBailout;
  final int defaultColorScheme;
  final double defaultCenterX;
  final double defaultCenterY;
  final double defaultZoom;
  final int maxIterations;
  final String category;
  final List<FractalParameter> extraParams;
  final List<FractalPreset> extraPresets;

  const EscapeTimeConfig({
    required this.id,
    required this.name,
    required this.shaderAsset,
    this.displayName,
    this.defaultIterations = 120,
    this.defaultBailout = 4.0,
    this.defaultColorScheme = 0,
    this.defaultCenterX = 0.0,
    this.defaultCenterY = 0.0,
    this.defaultZoom = 1.0,
    // Most runtime_effect escape-time shaders compile with a static loop cap of 500.
    // Keep the UI/params cap aligned with shader reality to avoid misleading controls.
    this.maxIterations = 500,
    this.category = 'Escape-Time',
    this.extraParams = const [],
    this.extraPresets = const [],
  });
}

/// Builds a [FractalModule] from a declarative [EscapeTimeConfig].
///
/// All standard escape-time fractals share the same uniform layout:
///   float 0: uTime
///   float 1-2: uResolution (vec2)
///   float 3-4: uCenter (vec2)
///   float 5: uZoom
///   float 6: uIterations
///   float 7: uBailout
///   float 8: uColorScheme
///   float 9: uTransparentBg
///   float 10+: extra params (in order)
///
/// This eliminates per-fractal Dart boilerplate.
FractalModule buildEscapeTimeModule(EscapeTimeConfig config) {
  assert(
    config.extraParams.every((p) => p.defaultValue is num),
    'Escape-time extra parameters must have numeric defaults because they are written to float uniforms.',
  );

  final defaults = _resolveEscapeTimeDefaults(config);

  final parameters = [
    CommonFractalParams.iterations(
      defaultValue: defaults.iterations,
      max: config.maxIterations,
    ),
    CommonFractalParams.bailout(defaultValue: config.defaultBailout),
    CommonFractalParams.colorScheme64(defaultValue: config.defaultColorScheme),
    ...config.extraParams,
  ];

  final defaultParams = <String, Object>{
    'iterations': defaults.iterations,
    'bailout': config.defaultBailout,
    'colorScheme': config.defaultColorScheme,
  };
  for (final p in config.extraParams) {
    defaultParams[p.id] = p.defaultValue;
  }

  final defaultPreset = FractalPreset(
    id: '${config.id}-default',
    moduleId: config.id,
    name: 'Default',
    params: defaultParams,
    view: FractalViewState(
      pan: Vector2(defaults.centerX, defaults.centerY),
      zoom: defaults.zoom,
      rotation: Vector3.zero(),
    ),
    createdAt: builtInPresetCreatedAt,
    isBuiltIn: true,
  );

  return FractalModule(
    id: config.id,
    displayName: config.displayName ?? ((_) => config.name),
    dimension: FractalDimension.twoD,
    shaderAsset: config.shaderAsset,
    parameters: parameters,
    defaultPreset: defaultPreset,
    builtInPresets: buildBuiltInPresetList(
      defaultPreset: defaultPreset,
      extraPresets: config.extraPresets,
    ),
    setUniforms: (shader, state, size, time) {
      shader.setFloat(EscapeTimeUniformSlots.time, time);
      shader.setFloat(EscapeTimeUniformSlots.resolutionX, size.width);
      shader.setFloat(EscapeTimeUniformSlots.resolutionY, size.height);
      shader.setFloat(EscapeTimeUniformSlots.centerX, state.view.pan.x);
      shader.setFloat(EscapeTimeUniformSlots.centerY, state.view.pan.y);
      shader.setFloat(EscapeTimeUniformSlots.zoom, state.view.zoom);
      shader.setFloat(EscapeTimeUniformSlots.iterations,
          readDouble(state.params, 'iterations', defaults.iterations));
      shader.setFloat(EscapeTimeUniformSlots.bailout,
          readDouble(state.params, 'bailout', config.defaultBailout));
      shader.setFloat(
          EscapeTimeUniformSlots.colorScheme,
          readDouble(state.params, 'colorScheme',
              config.defaultColorScheme.toDouble()));
      shader.setFloat(EscapeTimeUniformSlots.transparentBackground,
          state.transparentBackground ? 1.0 : 0.0);
      for (int i = 0; i < config.extraParams.length; i++) {
        final p = config.extraParams[i];
        shader.setFloat(EscapeTimeUniformSlots.extraStart + i,
            readDouble(state.params, p.id, (p.defaultValue as num).toDouble()));
      }
    },
  );
}

class _EscapeTimeDefaults {
  final double centerX;
  final double centerY;
  final double zoom;
  final double iterations;

  const _EscapeTimeDefaults({
    required this.centerX,
    required this.centerY,
    required this.zoom,
    required this.iterations,
  });
}

_EscapeTimeDefaults _resolveEscapeTimeDefaults(EscapeTimeConfig config) {
  var effectiveIterations = config.defaultIterations;
  var effectiveCenterX = config.defaultCenterX;
  var effectiveCenterY = config.defaultCenterY;
  var effectiveZoom = config.defaultZoom;

  if (config.extraPresets.isNotEmpty) {
    // If the module has curated presets, use the first curated preset as
    // default framing/iterations so each fractal starts with a distinctive
    // initial state instead of generic (0,0,1,120).
    final curated = config.extraPresets.first;
    final it = curated.params['iterations'];
    if (it is num) {
      effectiveIterations = it.toDouble();
    }
    // Only use first preset's view if no explicit center/zoom was configured.
    final hasExplicitView = config.defaultCenterX != 0.0 ||
        config.defaultCenterY != 0.0 ||
        config.defaultZoom != 1.0;
    if (!hasExplicitView) {
      effectiveCenterX = curated.view.pan.x;
      effectiveCenterY = curated.view.pan.y;
      effectiveZoom = curated.view.zoom;
    }
  } else {
    // For modules that still use baseline constructor defaults, generate
    // deterministic per-module defaults from the module id.
    final autoDefaults = _autoDefaultsForModule(config.id);
    final usesBaseIterations = config.defaultIterations == 120;
    final usesBaseCenter =
        config.defaultCenterX == 0.0 && config.defaultCenterY == 0.0;
    final usesBaseZoom = config.defaultZoom == 1.0;

    if (usesBaseIterations) {
      effectiveIterations = autoDefaults.iterations;
    }
    if (usesBaseCenter) {
      effectiveCenterX = autoDefaults.centerX;
      effectiveCenterY = autoDefaults.centerY;
    }
    if (usesBaseZoom) {
      effectiveZoom = autoDefaults.zoom;
    }
  }

  return _EscapeTimeDefaults(
    centerX: effectiveCenterX,
    centerY: effectiveCenterY,
    zoom: effectiveZoom.clamp(0.2, 32.0),
    iterations:
        effectiveIterations.clamp(20.0, config.maxIterations.toDouble()),
  );
}

class _AutoModuleDefaults {
  final double centerX;
  final double centerY;
  final double zoom;
  final double iterations;

  const _AutoModuleDefaults({
    required this.centerX,
    required this.centerY,
    required this.zoom,
    required this.iterations,
  });
}

_AutoModuleDefaults _autoDefaultsForModule(String moduleId) {
  final hash = _fnv1a32(moduleId);

  double unit(int shift) => ((hash >> shift) & 0xFF) / 255.0;

  // Keep defaults stable but non-generic per module:
  // - center around the classic Mandelbrot neighborhood
  // - moderate zoom that still shows structure
  // - varied iteration density for immediate detail diversity
  final centerX = -0.55 + (unit(0) - 0.5) * 0.5; // [-0.80, -0.30]
  final centerY = (unit(8) - 0.5) * 0.4; // [-0.20, 0.20]
  final zoom = 0.65 + unit(16) * 0.9; // [0.65, 1.55]
  final iterations = 110.0 + (hash % 131); // [110, 240]

  return _AutoModuleDefaults(
    centerX: centerX,
    centerY: centerY,
    zoom: zoom,
    iterations: iterations,
  );
}

int _fnv1a32(String text) {
  var hash = 0x811C9DC5;
  for (final codeUnit in text.codeUnits) {
    hash ^= codeUnit;
    hash = (hash * 0x01000193) & 0xFFFFFFFF;
  }
  return hash;
}

/// Uniform slot contracts shared by declarative module builders.
///
/// Keep these indices aligned with the matching fragment shaders. Centralizing
/// them makes shader/builder drift visible during review instead of burying the
/// contract as repeated magic numbers in setUniforms closures.
abstract final class EscapeTimeUniformSlots {
  static const int time = 0;
  static const int resolutionX = 1;
  static const int resolutionY = 2;
  static const int centerX = 3;
  static const int centerY = 4;
  static const int zoom = 5;
  static const int iterations = 6;
  static const int bailout = 7;
  static const int colorScheme = 8;
  static const int transparentBackground = 9;
  static const int extraStart = 10;
}

abstract final class Raymarched3DUniformSlots {
  static const int time = 0;
  static const int resolutionX = 1;
  static const int resolutionY = 2;
  static const int mouseX = 3;
  static const int mouseY = 4;
  static const int zoom = 5;
  static const int rotationX = 6;
  static const int rotationY = 7;
  static const int rotationZ = 8;
  static const int power = 9;
  static const int iterations = 10;
  static const int steps = 11;
  static const int bailout = 12;
  static const int colorScheme = 13;
  static const int fractalType = 14;
  static const int transparentBackground = 15;
}

import 'package:flutter_fractals/core/models/fractal_preset.dart';

/// Stable provenance marker for generated built-in presets.
///
/// Builder-owned presets are part of the app catalog, not user-created data, so
/// their metadata must be replayable across registry rebuilds and test runs.
final builtInPresetCreatedAt = DateTime.utc(2025, 1, 1);

/// Returns the builder-facing built-in preset list with replayable metadata.
///
/// Catalog entries often provide curated [extraPresets] for params/view only.
/// Normalize them here so callers cannot accidentally surface mutable-looking or
/// non-replayable presets in [FractalModule.builtInPresets].
List<FractalPreset> buildBuiltInPresetList({
  required FractalPreset defaultPreset,
  required List<FractalPreset> extraPresets,
}) {
  return [
    defaultPreset.copyWith(
        id: '${defaultPreset.moduleId}-classic', name: 'Classic'),
    ...extraPresets.map(_asReplayableBuiltInPreset),
  ];
}

FractalPreset _asReplayableBuiltInPreset(FractalPreset preset) {
  return preset.copyWith(
    createdAt: builtInPresetCreatedAt,
    isBuiltIn: true,
  );
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/builders/built_in_preset_contract.dart';
import 'package:flutter_fractals/core/modules/builders/uniform_layout.dart';
import 'package:flutter_fractals/core/modules/common_params.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/param_reader.dart';
import 'package:vector_math/vector_math.dart';

/// Declarative config for a standard 3D ray-marched fractal.
///
/// Adding a new ray-marched 3D fractal = one [Raymarched3DConfig] + one .frag shader.
/// No separate Dart module file needed.
///
/// All 3D ray-marched fractals share this uniform layout (matching mandelbulb.frag):
///   float 0:  uTime
///   float 1-2: uResolution (vec2)
///   float 3-4: uMousePos (vec2, unused placeholder)
///   float 5:  uZoom
///   float 6-8: uRotation (vec3)
///   float 9:  uPower
///   float 10: uIterations
///   float 11: uSteps
///   float 12: uBailout
///   float 13: uColorScheme
///   float 14: uFractalType
///   float 15: uTransparentBg
class Raymarched3DConfig {
  final String id;
  final String name;
  final ModuleNameBuilder? displayName;
  final String shaderAsset;
  final String category;

  // Default parameter values
  final double defaultPower;
  final double minPower;
  final double maxPower;
  final String powerLabel;
  final double defaultIterations;
  final double maxIterations;
  final double defaultSteps;
  final double defaultBailout;
  final int defaultColorScheme;
  final int maxColorScheme;
  final int defaultFractalType;
  final int maxFractalType;
  final List<FractalParamOption> fractalTypeOptions;
  final List<FractalPreset> extraPresets;

  const Raymarched3DConfig({
    required this.id,
    required this.name,
    required this.shaderAsset,
    this.displayName,
    this.category = '3D Fractals',
    this.defaultPower = 8.0,
    this.minPower = 2.0,
    this.maxPower = 12.0,
    this.powerLabel = 'Power',
    this.defaultIterations = 50,
    this.maxIterations = 100,
    this.defaultSteps = 120,
    this.defaultBailout = 2.0,
    this.defaultColorScheme = 0,
    this.maxColorScheme = 3,
    this.defaultFractalType = 0,
    this.maxFractalType = 0,
    this.fractalTypeOptions = const [],
    this.extraPresets = const [],
  });
}

/// Builds a [FractalModule] from a declarative [Raymarched3DConfig].
FractalModule buildRaymarched3DModule(Raymarched3DConfig config) {
  final parameters = [
    FractalParameter(
      id: 'power',
      label: (_) => config.powerLabel,
      type: FractalParamType.float,
      min: config.minPower,
      max: config.maxPower,
      step: 0.1,
      defaultValue: config.defaultPower,
    ),
    CommonFractalParams.iterations(
      defaultValue: config.defaultIterations,
      min: 5,
      max: config.maxIterations,
    ),
    FractalParameter(
      id: 'steps',
      label: (l10n) => l10n.paramSteps,
      type: FractalParamType.integer,
      min: 20,
      max: 200,
      step: 1,
      defaultValue: config.defaultSteps,
    ),
    CommonFractalParams.bailout(
      defaultValue: config.defaultBailout,
      min: 1.0,
      max: 8.0,
    ),
    CommonFractalParams.colorScheme4(
      defaultValue: config.defaultColorScheme.toDouble(),
      max: config.maxColorScheme,
    ),
    if (config.maxFractalType > 0)
      FractalParameter(
        id: 'fractalType',
        label: (_) => 'Variant',
        type: FractalParamType.enumeration,
        min: 0,
        max: config.maxFractalType.toDouble(),
        step: 1,
        defaultValue: config.defaultFractalType.toDouble(),
        options: config.fractalTypeOptions,
      ),
  ];

  final defaultParams = <String, Object>{
    'power': config.defaultPower,
    'iterations': config.defaultIterations,
    'steps': config.defaultSteps,
    'bailout': config.defaultBailout,
    'colorScheme': config.defaultColorScheme,
    if (config.maxFractalType > 0) 'fractalType': config.defaultFractalType,
  };

  final defaultPreset = FractalPreset(
    id: '${config.id}-default',
    moduleId: config.id,
    name: 'Default',
    params: defaultParams,
    view: FractalViewState(
      pan: Vector2.zero(),
      zoom: 1.0,
      rotation: Vector3(0.3, -0.4, 0.0),
    ),
    createdAt: builtInPresetCreatedAt,
    isBuiltIn: true,
  );

  return FractalModule(
    id: config.id,
    displayName: config.displayName ?? ((_) => config.name),
    dimension: FractalDimension.threeD,
    shaderAsset: config.shaderAsset,
    parameters: parameters,
    defaultPreset: defaultPreset,
    builtInPresets: buildBuiltInPresetList(
      defaultPreset: defaultPreset,
      extraPresets: config.extraPresets,
    ),
    setUniforms: (shader, state, size, time) {
      shader.setFloat(Raymarched3DUniformSlots.time, time);
      shader.setFloat(Raymarched3DUniformSlots.resolutionX, size.width);
      shader.setFloat(Raymarched3DUniformSlots.resolutionY, size.height);
      shader.setFloat(Raymarched3DUniformSlots.mouseX, 0.0); // unused
      shader.setFloat(Raymarched3DUniformSlots.mouseY, 0.0); // unused
      shader.setFloat(Raymarched3DUniformSlots.zoom, state.view.zoom);
      shader.setFloat(
          Raymarched3DUniformSlots.rotationX, state.view.rotation.x);
      shader.setFloat(
          Raymarched3DUniformSlots.rotationY, state.view.rotation.y);
      shader.setFloat(
          Raymarched3DUniformSlots.rotationZ, state.view.rotation.z);
      shader.setFloat(Raymarched3DUniformSlots.power,
          readDouble(state.params, 'power', config.defaultPower));
      shader.setFloat(Raymarched3DUniformSlots.iterations,
          readDouble(state.params, 'iterations', config.defaultIterations));
      shader.setFloat(Raymarched3DUniformSlots.steps,
          readDouble(state.params, 'steps', config.defaultSteps));
      shader.setFloat(Raymarched3DUniformSlots.bailout,
          readDouble(state.params, 'bailout', config.defaultBailout));
      shader.setFloat(
          Raymarched3DUniformSlots.colorScheme,
          readDouble(state.params, 'colorScheme',
              config.defaultColorScheme.toDouble()));
      shader.setFloat(
          Raymarched3DUniformSlots.fractalType,
          readDouble(state.params, 'fractalType',
              config.defaultFractalType.toDouble()));
      shader.setFloat(Raymarched3DUniformSlots.transparentBackground,
          state.transparentBackground ? 1.0 : 0.0);
    },
  );
}

